                        Divider().background(ThreadsTokens.threadsTextSecondary.opacity(0.3))
                    }
                }
            }
            .background(ThreadsTokens.threadsCanvas.ignoresSafeArea())
            .navigationTitle("Threads")
            .navigationBarTitleDisplayMode(.inline)
