                ToolbarItem(placement: .topBarLeading) { Image(systemName: "camera").foregroundStyle(ThreadsTokens.threadsLinkBlue) }
                ToolbarItem(placement: .topBarTrailing) {
                    HStack(spacing: 16) {
                        Image(systemName: "heart")
                        Image(systemName: "paperplane")
                    }
                }
            }
        }
    }
